-- =========================================================
-- NovaSalud V3.2.1 - Instalación completa de base de datos
-- Base independiente: bd_citasmedicas_v321
-- Ejecutar con usuario administrador de MySQL.
-- =========================================================
DROP DATABASE IF EXISTS bd_citasmedicas_v321;
CREATE DATABASE bd_citasmedicas_v321 DEFAULT CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci;
USE bd_citasmedicas_v321;
SET FOREIGN_KEY_CHECKS = 0;
DROP TABLE IF EXISTS auditoria_sistema;
DROP TABLE IF EXISTS configuracion_sistema;
DROP TABLE IF EXISTS caja_cierre;
DROP TABLE IF EXISTS pago_detalle;
DROP TABLE IF EXISTS pago;
DROP TABLE IF EXISTS atencion_medica;
DROP TABLE IF EXISTS historia_clinica;
DROP TABLE IF EXISTS tarifa_consulta;
DROP TABLE IF EXISTS cita;
DROP TABLE IF EXISTS horario;
DROP TABLE IF EXISTS usuario;
DROP TABLE IF EXISTS medico;
DROP TABLE IF EXISTS paciente;
DROP TABLE IF EXISTS especialidad;
SET FOREIGN_KEY_CHECKS = 1;

CREATE TABLE especialidad (
  id_especialidad INT NOT NULL AUTO_INCREMENT,
  nombre VARCHAR(100) NOT NULL,
  descripcion VARCHAR(255) NULL,
  usuario_registro VARCHAR(50) NULL,
  fecha_registro DATETIME NULL DEFAULT CURRENT_TIMESTAMP,
  usuario_actualizacion VARCHAR(50) NULL,
  fecha_actualizacion DATETIME NULL,
  estado_registro VARCHAR(15) NOT NULL DEFAULT 'ACTIVO',
  PRIMARY KEY (id_especialidad),
  UNIQUE KEY uk_especialidad_nombre (nombre)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

CREATE TABLE paciente (
  id_paciente INT NOT NULL AUTO_INCREMENT,
  dni VARCHAR(15) NOT NULL,
  nombres VARCHAR(100) NOT NULL,
  apellidos VARCHAR(100) NOT NULL,
  telefono VARCHAR(20) NULL,
  correo VARCHAR(100) NULL,
  direccion VARCHAR(255) NULL,
  fecha_nacimiento DATE NULL,
  sexo VARCHAR(10) NULL,
  contacto_emergencia VARCHAR(150) NULL,
  telefono_emergencia VARCHAR(20) NULL,
  historia_clinica_codigo VARCHAR(30) NULL,
  usuario_registro VARCHAR(50) NULL,
  fecha_registro DATETIME NULL DEFAULT CURRENT_TIMESTAMP,
  usuario_actualizacion VARCHAR(50) NULL,
  fecha_actualizacion DATETIME NULL,
  estado_registro VARCHAR(15) NOT NULL DEFAULT 'ACTIVO',
  PRIMARY KEY (id_paciente),
  UNIQUE KEY uk_paciente_dni (dni),
  UNIQUE KEY uk_paciente_hc (historia_clinica_codigo),
  KEY idx_paciente_nombre (apellidos, nombres)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

CREATE TABLE medico (
  id_medico INT NOT NULL AUTO_INCREMENT,
  nombres VARCHAR(100) NOT NULL,
  apellidos VARCHAR(100) NOT NULL,
  id_especialidad INT NOT NULL,
  dni VARCHAR(15) NULL,
  telefono VARCHAR(20) NULL,
  correo VARCHAR(100) NULL,
  cmp VARCHAR(30) NULL,
  duracion_cita_minutos INT NOT NULL DEFAULT 30,
  tolerancia_minutos INT NOT NULL DEFAULT 10,
  max_citas_dia INT NOT NULL DEFAULT 12,
  consultorio VARCHAR(80) NULL,
  usuario_registro VARCHAR(50) NULL,
  fecha_registro DATETIME NULL DEFAULT CURRENT_TIMESTAMP,
  usuario_actualizacion VARCHAR(50) NULL,
  fecha_actualizacion DATETIME NULL,
  estado_registro VARCHAR(15) NOT NULL DEFAULT 'ACTIVO',
  PRIMARY KEY (id_medico),
  UNIQUE KEY uk_medico_dni (dni),
  UNIQUE KEY uk_medico_cmp (cmp),
  KEY idx_medico_especialidad (id_especialidad),
  CONSTRAINT fk_medico_especialidad FOREIGN KEY (id_especialidad) REFERENCES especialidad(id_especialidad)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

CREATE TABLE usuario (
  id_usuario INT NOT NULL AUTO_INCREMENT,
  username VARCHAR(50) NOT NULL,
  password VARCHAR(100) NOT NULL,
  rol VARCHAR(20) NOT NULL,
  dni VARCHAR(15) NULL,
  nombres VARCHAR(100) NULL,
  apellidos VARCHAR(100) NULL,
  telefono VARCHAR(20) NULL,
  correo VARCHAR(100) NULL,
  cargo VARCHAR(80) NULL,
  id_medico INT NULL,
  session_version INT NOT NULL DEFAULT 1,
  usuario_registro VARCHAR(50) NULL,
  fecha_registro DATETIME NULL DEFAULT CURRENT_TIMESTAMP,
  usuario_actualizacion VARCHAR(50) NULL,
  fecha_actualizacion DATETIME NULL,
  ultimo_login DATETIME NULL,
  intentos_fallidos INT NOT NULL DEFAULT 0,
  bloqueado_hasta DATETIME NULL,
  estado_registro VARCHAR(15) NOT NULL DEFAULT 'ACTIVO',
  PRIMARY KEY (id_usuario),
  UNIQUE KEY uk_usuario_username (username),
  KEY idx_usuario_rol (rol),
  KEY idx_usuario_medico (id_medico),
  CONSTRAINT fk_usuario_medico FOREIGN KEY (id_medico) REFERENCES medico(id_medico)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

CREATE TABLE horario (
  id_horario INT NOT NULL AUTO_INCREMENT,
  id_medico INT NOT NULL,
  dia VARCHAR(20) NOT NULL,
  hora_inicio TIME NOT NULL,
  hora_fin TIME NOT NULL,
  usuario_registro VARCHAR(50) NULL,
  fecha_registro DATETIME NULL DEFAULT CURRENT_TIMESTAMP,
  usuario_actualizacion VARCHAR(50) NULL,
  fecha_actualizacion DATETIME NULL,
  estado_registro VARCHAR(15) NOT NULL DEFAULT 'ACTIVO',
  PRIMARY KEY (id_horario),
  KEY idx_horario_medico_dia (id_medico, dia),
  CONSTRAINT fk_horario_medico FOREIGN KEY (id_medico) REFERENCES medico(id_medico)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

CREATE TABLE tarifa_consulta (
  id_tarifa INT NOT NULL AUTO_INCREMENT,
  id_especialidad INT NOT NULL,
  nombre_tarifa VARCHAR(120) NOT NULL DEFAULT 'Consulta médica',
  monto DECIMAL(10,2) NOT NULL,
  moneda VARCHAR(10) NOT NULL DEFAULT 'PEN',
  vigencia_desde DATE NOT NULL,
  vigencia_hasta DATE NULL,
  estado_registro VARCHAR(15) NOT NULL DEFAULT 'ACTIVO',
  usuario_registro VARCHAR(50) NULL,
  fecha_registro DATETIME NULL DEFAULT CURRENT_TIMESTAMP,
  usuario_actualizacion VARCHAR(50) NULL,
  fecha_actualizacion DATETIME NULL,
  PRIMARY KEY (id_tarifa),
  UNIQUE KEY uk_tarifa_especialidad_inicio (id_especialidad, vigencia_desde),
  CONSTRAINT fk_tarifa_especialidad FOREIGN KEY (id_especialidad) REFERENCES especialidad(id_especialidad)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

CREATE TABLE cita (
  id_cita INT NOT NULL AUTO_INCREMENT,
  id_paciente INT NOT NULL,
  id_medico INT NOT NULL,
  id_especialidad INT NULL,
  id_tarifa_aplicada INT NULL,
  id_usuario_recepcionista INT NULL,
  monto_consulta DECIMAL(10,2) NULL,
  fecha DATE NOT NULL,
  hora TIME NOT NULL,
  duracion_minutos INT NOT NULL DEFAULT 30,
  hora_fin TIME GENERATED ALWAYS AS (ADDTIME(hora, SEC_TO_TIME(duracion_minutos * 60))) STORED,
  estado VARCHAR(20) NOT NULL DEFAULT 'PROGRAMADA',
  observaciones VARCHAR(255) NULL,
  usuario_registro VARCHAR(50) NULL,
  fecha_registro DATETIME NULL DEFAULT CURRENT_TIMESTAMP,
  usuario_actualizacion VARCHAR(50) NULL,
  fecha_actualizacion DATETIME NULL,
  estado_registro VARCHAR(15) NOT NULL DEFAULT 'ACTIVO',
  PRIMARY KEY (id_cita),
  UNIQUE KEY uk_cita_medico_fecha_hora (id_medico, fecha, hora),
  KEY idx_cita_paciente (id_paciente),
  KEY idx_cita_medico_fecha (id_medico, fecha),
  CONSTRAINT fk_cita_paciente FOREIGN KEY (id_paciente) REFERENCES paciente(id_paciente),
  CONSTRAINT fk_cita_medico FOREIGN KEY (id_medico) REFERENCES medico(id_medico),
  CONSTRAINT fk_cita_especialidad FOREIGN KEY (id_especialidad) REFERENCES especialidad(id_especialidad),
  CONSTRAINT fk_cita_tarifa FOREIGN KEY (id_tarifa_aplicada) REFERENCES tarifa_consulta(id_tarifa),
  CONSTRAINT fk_cita_recepcionista FOREIGN KEY (id_usuario_recepcionista) REFERENCES usuario(id_usuario)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

CREATE TABLE historia_clinica (
  id_historia INT NOT NULL AUTO_INCREMENT,
  id_paciente INT NOT NULL,
  codigo_historia VARCHAR(30) NOT NULL,
  antecedentes_generales VARCHAR(500) NULL,
  alergias VARCHAR(255) NULL,
  usuario_registro VARCHAR(50) NULL,
  fecha_registro DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,
  estado_registro VARCHAR(15) NOT NULL DEFAULT 'ACTIVO',
  PRIMARY KEY (id_historia),
  UNIQUE KEY uk_historia_paciente (id_paciente),
  UNIQUE KEY uk_historia_codigo (codigo_historia),
  CONSTRAINT fk_historia_paciente FOREIGN KEY (id_paciente) REFERENCES paciente(id_paciente)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

CREATE TABLE atencion_medica (
  id_atencion INT NOT NULL AUTO_INCREMENT,
  id_cita INT NOT NULL,
  id_medico INT NOT NULL,
  id_paciente INT NOT NULL,
  codigo_historia VARCHAR(30) NOT NULL,
  motivo_consulta VARCHAR(255) NULL,
  sintomas VARCHAR(700) NULL,
  diagnostico VARCHAR(700) NULL,
  tratamiento VARCHAR(700) NULL,
  receta_medica VARCHAR(700) NULL,
  indicaciones VARCHAR(700) NULL,
  fecha_atencion DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,
  estado_registro VARCHAR(15) NOT NULL DEFAULT 'ACTIVO',
  PRIMARY KEY (id_atencion),
  UNIQUE KEY uk_atencion_cita (id_cita),
  KEY idx_atencion_paciente (id_paciente),
  CONSTRAINT fk_atencion_cita FOREIGN KEY (id_cita) REFERENCES cita(id_cita),
  CONSTRAINT fk_atencion_medico FOREIGN KEY (id_medico) REFERENCES medico(id_medico),
  CONSTRAINT fk_atencion_paciente FOREIGN KEY (id_paciente) REFERENCES paciente(id_paciente)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

CREATE TABLE pago (
  id_pago INT NOT NULL AUTO_INCREMENT,
  codigo_pago VARCHAR(30) NULL,
  id_cita INT NOT NULL,
  monto_subtotal DECIMAL(10,2) GENERATED ALWAYS AS (ROUND(monto_total / 1.18, 2)) STORED,
  monto_igv DECIMAL(10,2) GENERATED ALWAYS AS (ROUND(monto_total - ROUND(monto_total / 1.18, 2), 2)) STORED,
  monto_total DECIMAL(10,2) NOT NULL DEFAULT 0.00,
  monto_pagado DECIMAL(10,2) NOT NULL DEFAULT 0.00,
  estado_pago VARCHAR(20) NOT NULL DEFAULT 'PENDIENTE',
  fecha_pago DATETIME NULL,
  id_usuario_cobro INT NULL,
  observacion VARCHAR(255) NULL,
  usuario_registro VARCHAR(50) NULL,
  fecha_registro DATETIME NULL DEFAULT CURRENT_TIMESTAMP,
  usuario_actualizacion VARCHAR(50) NULL,
  fecha_actualizacion DATETIME NULL,
  estado_registro VARCHAR(15) NOT NULL DEFAULT 'ACTIVO',
  PRIMARY KEY (id_pago),
  UNIQUE KEY uk_pago_cita (id_cita),
  UNIQUE KEY uk_pago_codigo (codigo_pago),
  CONSTRAINT fk_pago_cita FOREIGN KEY (id_cita) REFERENCES cita(id_cita),
  CONSTRAINT fk_pago_usuario_cobro FOREIGN KEY (id_usuario_cobro) REFERENCES usuario(id_usuario)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

CREATE TABLE pago_detalle (
  id_pago_detalle INT NOT NULL AUTO_INCREMENT,
  id_pago INT NOT NULL,
  metodo_pago VARCHAR(30) NOT NULL,
  monto DECIMAL(10,2) NOT NULL,
  numero_operacion VARCHAR(80) NULL,
  id_usuario_cajero INT NULL,
  fecha_operacion DATETIME NULL DEFAULT CURRENT_TIMESTAMP,
  observacion VARCHAR(255) NULL,
  estado_registro VARCHAR(15) NOT NULL DEFAULT 'ACTIVO',
  PRIMARY KEY (id_pago_detalle),
  CONSTRAINT fk_pago_detalle_pago FOREIGN KEY (id_pago) REFERENCES pago(id_pago),
  CONSTRAINT fk_pago_detalle_cajero FOREIGN KEY (id_usuario_cajero) REFERENCES usuario(id_usuario)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

CREATE TABLE caja_cierre (
  id_cierre INT NOT NULL AUTO_INCREMENT,
  fecha_caja DATE NOT NULL,
  id_usuario_caja INT NOT NULL,
  total_efectivo DECIMAL(10,2) NOT NULL DEFAULT 0.00,
  total_yape DECIMAL(10,2) NOT NULL DEFAULT 0.00,
  total_plin DECIMAL(10,2) NOT NULL DEFAULT 0.00,
  total_tarjeta DECIMAL(10,2) NOT NULL DEFAULT 0.00,
  total_transferencia DECIMAL(10,2) NOT NULL DEFAULT 0.00,
  total_general DECIMAL(10,2) NOT NULL DEFAULT 0.00,
  observacion VARCHAR(255) NULL,
  fecha_cierre DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,
  estado_cierre VARCHAR(20) NOT NULL DEFAULT 'CERRADO',
  PRIMARY KEY (id_cierre),
  UNIQUE KEY uk_caja_fecha_usuario (fecha_caja, id_usuario_caja),
  CONSTRAINT fk_caja_usuario FOREIGN KEY (id_usuario_caja) REFERENCES usuario(id_usuario)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

CREATE TABLE configuracion_sistema (
  clave VARCHAR(80) NOT NULL,
  valor VARCHAR(255) NOT NULL,
  descripcion VARCHAR(255) NULL,
  PRIMARY KEY (clave)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

CREATE TABLE auditoria_sistema (
  id_auditoria INT NOT NULL AUTO_INCREMENT,
  usuario VARCHAR(50) NULL,
  rol VARCHAR(30) NULL,
  accion VARCHAR(100) NOT NULL,
  modulo VARCHAR(100) NOT NULL,
  id_referencia INT NULL,
  descripcion VARCHAR(500) NULL,
  fecha DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,
  ip VARCHAR(50) NULL,
  PRIMARY KEY (id_auditoria)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

