-- Vistas de apoyo.
CREATE OR REPLACE VIEW vw_citas_completas AS
SELECT c.id_cita, p.dni AS paciente_dni, CONCAT(p.nombres,' ',p.apellidos) AS paciente,
       CONCAT(m.nombres,' ',m.apellidos) AS medico, e.nombre AS especialidad,
       c.fecha, c.hora, c.hora_fin, c.duracion_minutos, c.estado AS estado_cita,
       COALESCE(pg.estado_pago,'PENDIENTE') AS estado_pago, COALESCE(pg.monto_total,c.monto_consulta,0) AS monto_total,
       COALESCE(pg.monto_pagado,0) AS monto_pagado, COALESCE(u.username,'') AS recepcionista
FROM cita c
INNER JOIN paciente p ON c.id_paciente=p.id_paciente
INNER JOIN medico m ON c.id_medico=m.id_medico
INNER JOIN especialidad e ON c.id_especialidad=e.id_especialidad
LEFT JOIN usuario u ON c.id_usuario_recepcionista=u.id_usuario
LEFT JOIN pago pg ON c.id_cita=pg.id_cita AND pg.estado_registro='ACTIVO';

CREATE OR REPLACE VIEW vw_pagos_completos AS
SELECT pg.id_pago, pg.codigo_pago, pg.id_cita, c.fecha AS fecha_cita, c.hora AS hora_cita,
       CONCAT(pa.nombres,' ',pa.apellidos) AS paciente, pa.dni AS paciente_dni,
       CONCAT(m.nombres,' ',m.apellidos) AS medico, e.nombre AS especialidad,
       pg.monto_subtotal, pg.monto_igv, pg.monto_total, pg.monto_pagado, pg.estado_pago, pg.fecha_pago,
       COALESCE(u.username,'') AS usuario_cobro,
       COALESCE((SELECT GROUP_CONCAT(CONCAT(d.metodo_pago, ' S/ ', FORMAT(d.monto,2)) ORDER BY d.id_pago_detalle SEPARATOR ', ') FROM pago_detalle d WHERE d.id_pago=pg.id_pago AND d.estado_registro='ACTIVO'),'') AS metodos_pago
FROM pago pg
INNER JOIN cita c ON pg.id_cita=c.id_cita
INNER JOIN paciente pa ON c.id_paciente=pa.id_paciente
INNER JOIN medico m ON c.id_medico=m.id_medico
INNER JOIN especialidad e ON c.id_especialidad=e.id_especialidad
LEFT JOIN usuario u ON pg.id_usuario_cobro=u.id_usuario;

DELIMITER $$
DROP PROCEDURE IF EXISTS sp_eliminar_paciente$$
CREATE PROCEDURE sp_eliminar_paciente(IN p_id INT)
BEGIN
  UPDATE paciente SET estado_registro='INACTIVO', fecha_actualizacion=NOW() WHERE id_paciente=p_id;
END$$
DROP PROCEDURE IF EXISTS sp_eliminar_medico$$
CREATE PROCEDURE sp_eliminar_medico(IN p_id INT)
BEGIN
  UPDATE medico SET estado_registro='INACTIVO', fecha_actualizacion=NOW() WHERE id_medico=p_id;
END$$
DROP PROCEDURE IF EXISTS sp_eliminar_especialidad$$
CREATE PROCEDURE sp_eliminar_especialidad(IN p_id INT)
BEGIN
  UPDATE especialidad SET estado_registro='INACTIVO', fecha_actualizacion=NOW() WHERE id_especialidad=p_id;
END$$
DROP PROCEDURE IF EXISTS sp_eliminar_horario$$
CREATE PROCEDURE sp_eliminar_horario(IN p_id INT)
BEGIN
  UPDATE horario SET estado_registro='INACTIVO', fecha_actualizacion=NOW() WHERE id_horario=p_id;
END$$
DROP PROCEDURE IF EXISTS sp_listar_medicos$$
CREATE PROCEDURE sp_listar_medicos()
BEGIN
  SELECT m.id_medico, CONCAT(m.nombres,' ',m.apellidos) AS medico, e.nombre AS especialidad, m.telefono
  FROM medico m INNER JOIN especialidad e ON m.id_especialidad=e.id_especialidad
  WHERE m.estado_registro='ACTIVO' AND e.estado_registro='ACTIVO'
  ORDER BY e.nombre, m.apellidos;
END$$
DELIMITER ;

-- Usuario de aplicación y permisos mínimos.
CREATE USER IF NOT EXISTS 'usuario_citas'@'localhost' IDENTIFIED BY 'ISO/IEC27001';
ALTER USER 'usuario_citas'@'localhost' IDENTIFIED BY 'ISO/IEC27001';
GRANT SELECT, INSERT, UPDATE, DELETE, EXECUTE ON bd_citasmedicas_v321.* TO 'usuario_citas'@'localhost';
FLUSH PRIVILEGES;

-- Verificación rápida.
SELECT DATABASE() AS base_actual;
SELECT 'especialidad' AS tabla, COUNT(*) AS total FROM especialidad
UNION ALL SELECT 'medico', COUNT(*) FROM medico
UNION ALL SELECT 'paciente', COUNT(*) FROM paciente
UNION ALL SELECT 'usuario', COUNT(*) FROM usuario
UNION ALL SELECT 'cita', COUNT(*) FROM cita
UNION ALL SELECT 'pago', COUNT(*) FROM pago
UNION ALL SELECT 'pago_detalle', COUNT(*) FROM pago_detalle
UNION ALL SELECT 'atencion_medica', COUNT(*) FROM atencion_medica;

SELECT u.username, u.rol, u.estado_registro, u.id_medico, CONCAT(COALESCE(m.nombres,''),' ',COALESCE(m.apellidos,'')) AS medico_asociado, e.nombre AS especialidad
FROM usuario u LEFT JOIN medico m ON u.id_medico=m.id_medico LEFT JOIN especialidad e ON m.id_especialidad=e.id_especialidad
ORDER BY u.id_usuario;

SELECT 'Instalación NovaSalud V3.2.1 finalizada correctamente.' AS resultado;
